  insert into public.quizzes (course_id, title, description, position) values (v_course, 'Foundations Check (Modules 1–5)', 'Test your understanding of AI fundamentals and agent design.', 0) returning id into v_quiz;
  insert into public.quiz_questions (quiz_id, prompt, type, options, correct, points, position) values
    (v_quiz, 'Which agent orchestrates multiple sub-agents and decides routing?', 'single', '["Utility Agent","Supervisor Agent","Persona-based Agent","Tool User Agent"]'::jsonb, '[1]'::jsonb, 1, 0),
    (v_quiz, 'Which patterns involve more than one agent? (select all)', 'multiple', '["Single Agent","Hierarchical Agents","Agent-to-Agent (A2A)","Multi-Agent"]'::jsonb, '[1,2,3]'::jsonb, 2, 1),
    (v_quiz, 'When is a Human-in-the-Loop pattern used?', 'single', '["For simple one-tool tasks","When approval is required before an action","To translate text","To reduce token cost"]'::jsonb, '[1]'::jsonb, 1, 2);
  insert into public.quizzes (course_id, title, description, position) values (v_course, 'Tools & Integrations (Modules 7–14)', 'Check your knowledge of AI Agent tools and enterprise integrations.', 1) returning id into v_quiz;
