  insert into public.assignments (course_id, title, instructions, position) values (v_course, 'Build an Employee Management Agent', 'Using the Business Object Tool, build an agent that can search employees by name/department/role, update employee records via chat, and query leave balances. Secure BO access with role-based permissions. Submit a short write-up and a link to a recording or screenshots.', 0);
  insert into public.assignments (course_id, title, instructions, position) values (v_course, 'Invoice Approval Workflow', 'Design a Workflow Agent that receives invoice data, validates it against a PO (2-way/3-way match), routes to an approver via a Human Approval node, then posts a journal and emails confirmation on approval (or notifies the submitter on rejection). Submit your workflow export and notes.', 1);
  insert into public.assignments (course_id, title, instructions, position) values (v_course, 'Multi-Agent HR Assistant (Capstone)', 'Build a Supervisor agent that routes to Leave, Payroll and Recruitment specialist agents, each with dedicated BO/REST tools and shared context for multi-turn conversations. Submit a link to your working demo.', 2);
